                            <button className="inline-flex items-center px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 transition-colors text-sm font-medium">
                                <span className="mr-2">🔑</span>
                                Change Password
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
