                                        <div className="flex items-center justify-between">
                                            <h4 className={`text-sm font-semibold transition-colors duration-300 ${
                                                isDarkMode ? 'text-gray-100' : 'text-gray-900'
                                            }`}>{t('admin.activity.newContactMessage')}</h4>
